Sure! Here's a valid **JSON Schema** for a **Customer Profile** that defines the structure and constraints for customer data:

```json
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "Customer Profile",
  "type": "object",
  "properties": {
    "id": {
      "type": "integer",
      "description": "Unique identifier for the customer"
    },
    "firstName": {
      "type": "string",
      "description": "First name of the customer"
    },
    "lastName": {
      "type": "string",
      "description": "Last name of the customer"
    },
    "email": {
      "type": "string",
      "format": "email",
      "description": "Email address of the customer"
    },
    "phone": {
      "type": "string",
      "description": "Phone number of the customer"
    },
    "address": {
      "type": "object",
      "properties": {
        "street": {
          "type": "string"
        },
        "city": {
          "type": "string"
        },
        "state": {
          "type": "string"
        },
        "postalCode": {
          "type": "string"
        },
        "country": {
          "type": "string"
        }
      },
      "required": ["street", "city", "state", "postalCode", "country"]
    },
    "dateOfBirth": {
      "type": "string",
      "format": "date",
      "description": "Date of birth in ISO 8601 format (YYYY-MM-DD)"
    },
    "registrationDate": {
      "type": "string",
      "format": "date-time",
      "description": "Date and time the customer was registered (ISO 8601 format)"
    },
    "preferences": {
      "type": "object",
      "properties": {
        "newsletter": {
          "type": "boolean",
          "description": "Whether the customer wants to receive the newsletter"
        },
        "marketing": {
          "type": "boolean",
          "description": "Whether the customer agrees to marketing communications"
        }
      }
    }
  },
  "required": ["id", "firstName", "lastName", "email", "address", "dateOfBirth"]
}
```

### Key Features:
- **id**: Unique
